 * A subarray can be sorted by cyclic shifts if and only if the elements in it
 * are a permutation of a sequence that is "almost sorted" in a cyclic sense.
 * More precisely, if we sort the subarray to get the target sorted version,
 * the original subarray must be a cyclic shift of the target sorted version.
 */
fun canSortSubarray(subarray: List<Int>): Boolean {
    val k = subarray.size
    if (k == 1) return true // A single element is always sorted

    // 1. Get the sorted version
    val sortedSubarray = subarray.sorted()

    // 2. Check if the original subarray is a cyclic shift of the sorted subarray
    // Concatenate the sorted subarray with itself: sortedSubarray + sortedSubarray
    val doubledSorted = sortedSubarray + sortedSubarray

    // Convert the original subarray to an array for easier searching (though List works too)
    val originalArray = subarray.toTypedArray()

    // Check every possible start index in the doubled array (from 0 to k-1)
    for (start in 0 until k) {
        var match = true
        for (i in 0 until k) {
            // Check if originalArray[i] matches the element at position (start + i) in doubledSorted
            if (originalArray[i] != doubledSorted[start + i]) {
                match = false
                break
            }
        }
        if (match) {
            return true
        }
    }
    return false
}

